29		const parseLogCall = (logCall: string, delimiter: string): unknown => {
30			const parts = logCall.split(delimiter);
31			if (parts.length < 2 || !parts[1]) {
32				throw new Error(`Expected log call to contain delimiter: ${delimiter}`);
33			}
34			return JSON.parse(parts[1]);
35		};
36	
37		const getLogCall = (callIndex: number, argIndex = 0): string => {
38			const call = mockLoggerInstance.log.mock.calls[callIndex] as unknown[];
39			if (typeof call[argIndex] !== 'string') {
40				throw new Error(
41					`Expected log call at index ${callIndex} to exist and have string argument at index ${argIndex}`,
42				);
43			}
44			return String(call[argIndex]);
45		};
46	
47		const getErrorCall = (callIndex: number, argIndex = 0): string => {
48			const call = mockLoggerInstance.error.mock.calls[callIndex] as unknown[];
49			if (typeof call[argIndex] !== 'string') {
50				throw new Error(
51					`Expected error call at index ${callIndex} to exist and have string argument at index ${argIndex}`,
52				);
53			}
54			return String(call[argIndex]);
55		};
56	
57		describe('Basic Functionality', () => {
